//! The egui control panel (the only egui UI outside the mode builders).

use crate::*;

/// Material Symbols glyph codepoints — GENERATED by `build.rs` from the font manifest (U.2.1), so the
/// glyphs the panel draws are exactly the ones subset into `MaterialSymbols-subset.ttf`. Do not edit.
#[allow(dead_code)] // ADD/DELETE/EYE/… are wired as button icons in U.2; generated as one set.
mod icons {
    include!(concat!(env!("OUT_DIR"), "/icon_glyphs.rs"));
}

/// Install the bundled Material Symbols subset as a LOWEST-priority fallback on both font families, so
/// icon codepoints (the cut chevron, and the U.2 button glyphs) resolve inside any label while text
/// keeps the default font. Runs ONCE — `add_font` persists in the egui context (U.2.1).
pub(crate) fn install_fonts(mut contexts: EguiContexts, mut done: Local<bool>) {
    if *done {
        return;
    }
    let Ok(ctx) = contexts.ctx_mut() else {
        return;
    };
    use egui::epaint::text::{FontPriority, InsertFontFamily};
    ctx.add_font(egui::epaint::text::FontInsert::new(
        "material-symbols",
        egui::FontData::from_static(include_bytes!(concat!(
            env!("CARGO_MANIFEST_DIR"),
            "/assets/fonts/MaterialSymbols-subset.ttf"
        ))),
        vec![
            InsertFontFamily {
                family: egui::FontFamily::Proportional,
                priority: FontPriority::Lowest,
            },
            InsertFontFamily {
                family: egui::FontFamily::Monospace,
                priority: FontPriority::Lowest,
            },
        ],
    ));
    *done = true;
}

/// The panel's outbound message writers, bundled so `panel_ui` spends ONE system param on all
/// three (Bevy caps a system at 16 params).
#[derive(SystemParam)]
pub(crate) struct PanelWriters<'w> {
    pub(crate) switch: MessageWriter<'w, SwitchFile>,
    pub(crate) autoplace: MessageWriter<'w, AutoPlace>,
    pub(crate) cmd: MessageWriter<'w, PanelCmd>,
}

/// The whole control panel (U.3), immediate-mode: an app-wide top tab bar + bottom status bar +
/// a left egui panel whose contents route on the active `Tab` (Model / Parts / Orientation / Export).
/// Cheap edits mutate in place; a heavy action (needing params beyond the panel's own) writes a
/// `PanelCmd` its dedicated system handles. Writes `PanelSeam` after drawing so `orbit` yields the
/// pointer over the panels and `split_viewport` insets the 3D camera inside all three bars.
// TODO(U.2): the Material Symbols icon font — text labels ("+"/"on"/"off"/"del"/"conn") for now.
#[allow(clippy::too_many_arguments)]
pub(crate) fn panel_ui(
    mut contexts: EguiContexts,
    mut parts: ResMut<Parts>,
    mut active_part: ResMut<ActivePart>,
    mut active: ResMut<ActiveConn>,
    mut edit: ResMut<EditCut>,
    mut tab: ResMut<Tab>,
    files: Res<FileList>,
    status: Res<Status>,
    job: Res<Job>,
    mut open_dialog: ResMut<OpenDialog>,
    mut editor: ResMut<EditorBuf>,
    time: Res<Time>,
    print_pieces: Res<PrintPieces>,
    mut writers: PanelWriters,
    mut seam: ResMut<PanelSeam>,
) {
    let Ok(ctx) = contexts.ctx_mut() else {
        return;
    };
    // A delete defers past the row loop (index stability), tagged with the PART it belongs to (T.2b).
    let mut to_remove: Option<(usize, usize)> = None;
    // A per-piece "reset to auto" (U.3.4) likewise defers past the Orientation list's `parts` borrow.
    let mut reset_orient: Option<(usize, PieceKey)> = None;
    // egui 0.35 panels show INTO a Ui, not the Context — wrap the viewport in a background-layer Ui
    // first (the bevy_egui side_panel pattern) so the panels overlay the 3D view.
    let mut viewport = egui::Ui::new(
        ctx.clone(),
        egui::Id::new("panel_viewport"),
        egui::UiBuilder::new()
            .layer_id(egui::LayerId::background())
            .max_rect(ctx.viewport_rect()),
    );
    // TOP BAR (U.3): the app-wide workflow tabs — Model → Parts → Orientation → Export. Sets the
    // active `Tab` (the source of truth the left panel routes on); the ACTIVE tab reads green + bold.
    let top = egui::Panel::top("topbar").show(&mut viewport, |ui| {
        ui.horizontal(|ui| {
            ui.heading("fab-gui");
            ui.separator();
            for (t, label) in Tab::ALL {
                let on = *tab == t;
                let text = if on {
                    egui::RichText::new(label)
                        .color(egui::Color32::from_rgb(120, 220, 140))
                        .strong()
                } else {
                    egui::RichText::new(label)
                };
                if ui.selectable_label(on, text).clicked() {
                    *tab = t;
                }
            }
        });
    });
    // BOTTOM BAR (U.3): the traditional status line — pulses blue while a background render/slice runs.
    let bottom = egui::Panel::bottom("statusbar").show(&mut viewport, |ui| {
        if job.0.is_some() {
            let p = ((ui.input(|i| i.time) * 5.0).sin() * 0.5 + 0.5) as f32;
            let col =
                egui::Color32::from_rgb((115.0 + 115.0 * p) as u8, (165.0 + 75.0 * p) as u8, 255);
            ui.colored_label(col, status.0.as_str());
            ui.ctx().request_repaint();
        } else {
            ui.label(status.0.as_str());
        }
    });
    // LEFT PANEL (U.3): the active tab's controls.
    let panel = egui::Panel::left("panel")
        .resizable(true)
        .default_size(220.0)
        .show(&mut viewport, |ui| {
            match *tab {
                Tab::Model => {
                    // FILE TABS (U.3.2): the open files as tabs + a ＋ that reopens the folder picker.
                    ui.horizontal_wrapped(|ui| {
                        for (i, path) in files.files.iter().enumerate() {
                            let name = path
                                .file_name()
                                .map(|s| s.to_string_lossy().into_owned())
                                .unwrap_or_else(|| "?".into());
                            let on = files.active == Some(i);
                            let text = if on {
                                egui::RichText::new(name)
                                    .color(egui::Color32::from_rgb(120, 220, 140))
                                    .strong()
                            } else {
                                egui::RichText::new(name)
                            };
                            if ui.selectable_label(on, text).clicked() {
                                writers.switch.write(SwitchFile(i));
                            }
                        }
                        if ui.button(icons::ADD).clicked() && open_dialog.0.is_none() {
                            open_dialog.0 = Some(AsyncComputeTaskPool::get().spawn(async move {
                                rfd::AsyncFileDialog::new()
                                    .pick_folder()
                                    .await
                                    .map(|h| h.path().to_path_buf())
                            }));
                        }
                    });
                    ui.separator();
                    // Save (explicit, desktop) + jump to OpenSCAD. The buffer renders live; the file
                    // on disk only changes here.
                    ui.horizontal(|ui| {
                        if ui
                            .add_enabled(editor.dirty, egui::Button::new("Save"))
                            .clicked()
                            && std::fs::write(&editor.path, editor.text.as_bytes()).is_ok()
                        {
                            editor.dirty = false;
                        }
                        if editor.dirty {
                            ui.colored_label(egui::Color32::from_rgb(224, 168, 96), "● unsaved");
                        }
                    });
                    // The code editor — its buffer IS the render source (debounced preview, U.3.2).
                    // `auto_shrink` off + sizing to the remaining space so it FILLS the panel, not just
                    // the text height (else a short file leaves the panel half-empty).
                    egui::ScrollArea::vertical()
                        .auto_shrink([false, false])
                        .show(ui, |ui| {
                            let resp = ui.add_sized(
                                ui.available_size(),
                                egui::TextEdit::multiline(&mut editor.text)
                                    .code_editor()
                                    .desired_width(f32::INFINITY),
                            );
                            if resp.changed() {
                                editor.dirty = true;
                                editor.edited_at = Some(time.elapsed_secs_f64());
                            }
                        });
                }
                Tab::Parts => {
                    // THE DRILL (U.3.3): part → cut → connector, top to bottom. A collapsing section
                    // per top-level part (green + bold = active); its body flattens to that part's
                    // cuts; expanding a cut (▼) reveals its connectors inline. The active part drives
                    // the slice systems + cut-plane overlays, so an edit reslices the right part.
                    ui.label(
                        egui::RichText::new("parts · cuts · connectors")
                            .small()
                            .weak(),
                    );
                    let n = parts.0.len();
                    let mut autoplace_req = false;
                    for i in 0..n {
                        let is_active = active_part.0 == i;
                        let pcs = piece_estimate(&parts.0[i].cuts);
                        let label = format!(
                            "{} · {} pc{}",
                            part_label(&parts.0[i].name, i),
                            pcs,
                            if pcs == 1 { "" } else { "s" }
                        );
                        // The ACTIVE part reads green + bold — a clear marker that doesn't collide
                        // with egui's collapse triangle the way a "▶" prefix did.
                        let header = if is_active {
                            egui::RichText::new(label)
                                .color(egui::Color32::from_rgb(120, 220, 140))
                                .strong()
                        } else {
                            egui::RichText::new(label)
                        };
                        let mut select = false;
                        let resp = egui::CollapsingHeader::new(header)
                            .id_salt(("part", i))
                            .default_open(is_active)
                            .show(ui, |ui| {
                                select |= part_cut_editor(
                                    ui,
                                    &mut parts.0[i],
                                    i,
                                    is_active,
                                    &mut edit,
                                    &mut active,
                                    &mut to_remove,
                                    &mut autoplace_req,
                                );
                            });
                        if select || resp.header_response.clicked() {
                            active_part.0 = i;
                            parts.set_changed(); // a pure selection must refresh the active-part visuals
                        }
                    }
                    // An Auto-place click inside the drill bubbles up here (the writer can't cross the
                    // part-borrow into `part_cut_editor`).
                    if autoplace_req {
                        writers.autoplace.write(AutoPlace);
                    }
                    ui.separator();
                    // Slicing itself is reactive (background reslice on cut changes) — these are the
                    // only two Parts actions, and each ALWAYS has an effect: no dead buttons (U.3.15).
                    let (has_cuts, spread) = {
                        let p = &parts.0[active_part.0];
                        (p.cuts.list.iter().any(|c| c.enabled), p.spread)
                    };
                    // Reset-to-auto: throw away this part's cuts+connectors and re-derive the full plan
                    // (fit-to-bed cuts + auto-placed connectors, or WHOLE if it fits).
                    if ui.button("Reset to auto").clicked() {
                        writers.cmd.write(PanelCmd::AutoSlice);
                    }
                    // Explode is a per-part VIEW toggle, enabled only when the part has pieces to fan —
                    // a part that fits the bed is whole, so there's nothing to explode.
                    if ui
                        .add_enabled(
                            has_cuts,
                            egui::Button::new(if spread > 0.0 { "Assemble" } else { "Explode" }),
                        )
                        .clicked()
                    {
                        writers.cmd.write(PanelCmd::ToggleView);
                    }
                    // Slice summary (mockup's eg-status): part count + estimated piece total.
                    let total: usize = parts.0.iter().map(|p| piece_estimate(&p.cuts)).sum();
                    ui.label(
                        egui::RichText::new(format!(
                            "{n} part{} · {total} pieces",
                            if n == 1 { "" } else { "s" }
                        ))
                        .small()
                        .weak(),
                    );
                }
                Tab::Orientation => {
                    ui.label(egui::RichText::new("print orientation").small().weak());
                    ui.label(
                        egui::RichText::new(
                            "click a piece in the view to set which face prints down",
                        )
                        .small()
                        .weak(),
                    );
                    ui.separator();
                    // Every printable piece across ALL parts (co-pack), each flagged flat (a manual
                    // orientation set) vs auto (still the least-support auto-pick). The mode + 3D
                    // click-to-orient already run while this tab is up; this is the readout + per-piece
                    // reset. `PrintPieces` is None until the first slice lands.
                    match print_pieces.0.as_ref() {
                        None => {
                            ui.label(
                                egui::RichText::new("slice a part first — no pieces yet")
                                    .small()
                                    .weak(),
                            );
                        }
                        Some(pieces) => {
                            let mut flat = 0usize;
                            let mut nth: std::collections::HashMap<usize, usize> =
                                std::collections::HashMap::new();
                            for (part, pp) in pieces {
                                let Some(p) = parts.0.get(*part) else {
                                    continue;
                                };
                                let key = (pp.piece, pp.comp);
                                let manual = p.orient.manual.contains(&key);
                                if manual {
                                    flat += 1;
                                }
                                let n = {
                                    let c = nth.entry(*part).or_insert(0);
                                    *c += 1;
                                    *c
                                };
                                let label = format!("{} · pc {}", part_label(&p.name, *part), n);
                                ui.horizontal(|ui| {
                                    ui.label(label);
                                    ui.with_layout(
                                        egui::Layout::right_to_left(egui::Align::Center),
                                        |ui| {
                                            if manual {
                                                // manual → seated flat; a click resets it to the auto-pick.
                                                if ui
                                                    .small_button("↺")
                                                    .on_hover_text("reset to auto")
                                                    .clicked()
                                                {
                                                    reset_orient = Some((*part, key));
                                                }
                                                ui.label(
                                                    egui::RichText::new("flat ✓")
                                                        .monospace()
                                                        .color(egui::Color32::from_rgb(
                                                            120, 220, 140,
                                                        )),
                                                );
                                            } else {
                                                ui.label(
                                                    egui::RichText::new("auto").monospace().color(
                                                        egui::Color32::from_rgb(224, 168, 96),
                                                    ),
                                                );
                                            }
                                        },
                                    );
                                });
                            }
                            ui.separator();
                            ui.label(
                                egui::RichText::new(format!(
                                    "{} pieces · {} seated flat",
                                    pieces.len(),
                                    flat
                                ))
                                .small()
                                .weak(),
                            );
                        }
                    }
                }
                Tab::Export => {
                    if ui.button("Export plates").clicked() {
                        writers.cmd.write(PanelCmd::Export);
                    }
                    if ui.button("Publish").clicked() {
                        writers.cmd.write(PanelCmd::Publish);
                    }
                    // The co-pack plate preview lands in U.3.5.
                }
            }
            // Fill the panel to full height on every tab so its frame reaches the status bar (U.3.2).
            ui.add_space(ui.available_height());
        });
    if let Some((p, idx)) = to_remove {
        if let Some(part) = parts.0.get_mut(p) {
            remove_cut(&mut part.cuts, &mut part.conns, idx);
        }
    }
    if let Some((part, key)) = reset_orient {
        if let Some(p) = parts.0.get_mut(part) {
            p.orient.reset(key);
        }
        parts.set_changed(); // re-seat this piece at the auto-pick (sync_orientation guards on is_changed)
    }
    seam.width_px = panel.response.rect.width() * ctx.pixels_per_point();
    seam.top_px = top.response.rect.height() * ctx.pixels_per_point();
    seam.bottom_px = bottom.response.rect.height() * ctx.pixels_per_point();
    seam.over_ui = ctx.egui_wants_pointer_input() || ctx.is_pointer_over_egui();
}

/// Render one part's cut + connector drill — the middle and inner levels of the part → cut →
/// connector tree (U.3.3). Each cut is a flat stack-order row whose `▸/▼` triangle expands its
/// connectors inline (and drives the 2D face-on cross-section editor through `edit`); a trailing
/// `+X/+Y/+Z` strip adds a plane. Returns `true` if the user TOUCHED anything, so the caller makes
/// this part active and the reactive slice follows the edit. `part_idx` tags a deferred delete with
/// its owner; `autoplace_req` bubbles an Auto-place click up to the caller's message writer (which
/// can't cross the `part` borrow).
#[allow(
    clippy::too_many_arguments,
    reason = "the drill threads one part plus edit/active/remove/autoplace channels; a bundle struct just relocates the arity, not the noise"
)]
pub(crate) fn part_cut_editor(
    ui: &mut egui::Ui,
    part: &mut Part,
    part_idx: usize,
    is_active_part: bool,
    edit: &mut EditCut,
    active: &mut ActiveConn,
    to_remove: &mut Option<(usize, usize)>,
    autoplace_req: &mut bool,
) -> bool {
    let mut touched = false;
    // CUTS — a flat stack-order list (the connector `.cut` field indexes THIS order, so don't
    // reorder). Only the active part edits connectors, so its `▼` state gates the inline drill.
    let n = part.cuts.list.len();
    for idx in 0..n {
        let axis = part.cuts.list[idx].axis;
        let editing = is_active_part && edit.0 == Some(idx);
        let is_cut_active = idx == part.cuts.active;
        ui.horizontal(|ui| {
            // Expand this cut's connectors (and enter the 2D face-on editor — both ride `edit`). A real
            // Material Symbols glyph from the build.rs-managed icon font: chevron_right when collapsed,
            // expand_more when open (U.2.1). Frameless clickable label = a bare chevron, per the mockup.
            let glyph = if editing {
                icons::EXPAND_MORE
            } else {
                icons::CHEVRON_RIGHT
            };
            if ui
                .add(egui::Label::new(glyph).sense(egui::Sense::click()))
                .clicked()
            {
                edit.0 = if editing { None } else { Some(idx) };
                part.cuts.active = idx;
                touched = true;
            }
            let name = format!("{} cut @", axis.label());
            ui.label(if is_cut_active {
                egui::RichText::new(name).strong()
            } else {
                egui::RichText::new(name)
            });
            let mut at = part.cuts.list[idx].at;
            if ui.add(egui::DragValue::new(&mut at).speed(0.5)).changed() {
                part.cuts.list[idx].at = clamp_to_bounds(at, axis, &part.bounds);
                part.cuts.active = idx;
                touched = true;
            }
            let en = part.cuts.list[idx].enabled;
            if ui
                .selectable_label(en, if en { "on" } else { "off" })
                .clicked()
            {
                part.cuts.list[idx].enabled = !en;
                touched = true;
            }
            if ui
                .button(egui::RichText::new("del").color(egui::Color32::from_rgb(230, 130, 130)))
                .clicked()
            {
                *to_remove = Some((part_idx, idx));
                touched = true;
            }
        });
        // CONNECTORS — inline under the expanded cut (the old Connectors mode, now nested). Sets the
        // active connector TYPE + does auto-place / clear for THIS cut; click-to-place lives in the
        // 2D editor on the same `edit` state.
        if editing {
            ui.indent(("conn", idx), |ui| {
                ui.label(egui::RichText::new("connectors — this cut").small().weak());
                ui.horizontal(|ui| {
                    if ui
                        .selectable_label(active.kind == fab::ConnKind::Onion, "Onion")
                        .clicked()
                    {
                        active.kind = fab::ConnKind::Onion;
                    }
                    if ui
                        .selectable_label(active.kind == fab::ConnKind::Bolt, "Bolt")
                        .clicked()
                    {
                        active.kind = fab::ConnKind::Bolt;
                    }
                });
                if active.kind == fab::ConnKind::Bolt {
                    ui.horizontal(|ui| {
                        for s in [Screw::M3, Screw::M4, Screw::M5] {
                            if ui.selectable_label(active.screw == s, s.label()).clicked() {
                                active.screw = s;
                            }
                        }
                    });
                }
                ui.horizontal(|ui| {
                    if ui.button("Auto-place").clicked() {
                        *autoplace_req = true;
                    }
                    if ui.button("Clear").clicked() {
                        part.conns.list.retain(|c| c.cut != idx);
                    }
                });
            });
        }
    }
    // ADD PLANES — one combined +X/+Y/+Z strip (replaces the old per-axis "+" sections), matching
    // the v4 mockup. A new plane drops at the part's mid-span on that axis.
    ui.horizontal(|ui| {
        for axis in [Axis::X, Axis::Y, Axis::Z] {
            if ui.button(format!("+{}", axis.label())).clicked() {
                if let Some((mn, mx)) = part.bounds.0 {
                    let at = comp((mn + mx) * 0.5, axis.index());
                    part.cuts.list.push(CutDef {
                        axis,
                        at,
                        enabled: true,
                    });
                    part.cuts.active = part.cuts.list.len() - 1;
                    touched = true;
                }
            }
        }
    });
    touched
}

/// The accordion label for part `i`: its provenance name (the top-level module/function that made
/// it) capped to a stable width + an ordinal suffix — `wall_sliced·1`, `frame·2` — or a generic
/// `Part N` when the part is anonymous (a bare block / an ambiguous split). The suffix keeps labels
/// short + uniform and disambiguates two parts from the SAME module (T.2b).
pub(crate) fn part_label(name: &Option<String>, i: usize) -> String {
    const CAP: usize = 12; // chars, before the ·ordinal — keeps the accordion column tidy
    match name {
        Some(n) if n.chars().count() > CAP => {
            let short: String = n.chars().take(CAP - 1).collect();
            format!("{short}…·{}", i + 1)
        }
        Some(n) => format!("{n}·{}", i + 1),
        None => format!("Part {}", i + 1),
    }
}

/// A rough printable-piece count for a part's cut stack — the product over axes of (enabled cuts on
/// that axis + 1). Ignores connected-components (a presliced blob reads as 1 until sliced), so it's
/// a fast accordion label, not the exact plate count.
pub(crate) fn piece_estimate(cuts: &Cuts) -> usize {
    [Axis::X, Axis::Y, Axis::Z]
        .iter()
        .map(|&ax| {
            cuts.list
                .iter()
                .filter(|c| c.enabled && c.axis == ax)
                .count()
                + 1
        })
        .product()
}
